import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from './AuthContext';
import './CartModal.css';

const CartModal = ({ isOpen, onClose }) => {
    const [cart, setCart] = useState({ items: [], total: 0, count: 0 });
    const [loading, setLoading] = useState(false);
    const [showCheckout, setShowCheckout] = useState(false);
    const [orderForm, setOrderForm] = useState({
        shipping_name: '',
        shipping_phone: '',
        shipping_address: '',
        note: '',
        payment_method: 'cod'
    });
    const { user } = useAuth();

    useEffect(() => {
        if (isOpen && user) {
            fetchCart();
        }
    }, [isOpen, user]);

    const fetchCart = async () => {
        try {
            const res = await axios.get('http://localhost:5000/api/cart');
            setCart(res.data);
        } catch (error) {
            console.error('Lб»—i tбєЈi giб»Џ hГ ng:', error);
        }
    };

    const updateQuantity = async (cartId, quantity) => {
        if (quantity < 1) {
            await removeItem(cartId);
            return;
        }
        try {
            await axios.put(`http://localhost:5000/api/cart/${cartId}`, { quantity });
            fetchCart();
        } catch (error) {
            console.error('Lб»—i cбє­p nhбє­t:', error);
        }
    };

    const removeItem = async (cartId) => {
        try {
            await axios.delete(`http://localhost:5000/api/cart/${cartId}`);
            fetchCart();
        } catch (error) {
            console.error('Lб»—i xГіa:', error);
        }
    };

    const handleOrderSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const res = await axios.post('http://localhost:5000/api/orders', orderForm);
            if (res.data.success) {
                alert(`вњ… Дђбє·t hГ ng thГ nh cГґng! MГЈ Д‘ЖЎn: ${res.data.order.order_code}`);
                onClose();
                setShowCheckout(false);
                setCart({ items: [], total: 0, count: 0 });
            }
        } catch (error) {
            alert('вќЊ Lб»—i: ' + (error.response?.data?.message || 'Дђбє·t hГ ng thбєҐt bбєЎi'));
        } finally {
            setLoading(false);
        }
    };

    const formatPrice = (price) => {
        return price.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.') + ' в‚«';
    };

    if (!isOpen) return null;

    return (
        <div className="cart-modal-overlay" onClick={onClose}>
            <div className="cart-modal-container" onClick={e => e.stopPropagation()}>
                <div className="cart-modal-header">
                    <h2>рџ›’ Giб»Џ hГ ng cб»§a bбєЎn</h2>
                    <button className="cart-modal-close" onClick={onClose}>&times;</button>
                </div>

                {!showCheckout ? (
                    <>
                        <div className="cart-items">
                            {cart.items?.length === 0 ? (
                                <div className="empty-cart">
                                    <p>рџ›ЌпёЏ Giб»Џ hГ ng trб»‘ng</p>
                                    <button onClick={onClose} className="continue-shopping">
                                        Tiбєїp tб»Ґc mua sбєЇm
                                    </button>
                                </div>
                            ) : (
                                cart.items?.map(item => (
                                    <div key={item.cart_id} className="cart-item">
                                        <img src={item.image_url} alt={item.name} />
                                        <div className="cart-item-info">
                                            <h4>{item.name}</h4>
                                            <p>{item.brand}</p>
                                            <p className="cart-item-price">{formatPrice(item.price)}</p>
                                        </div>
                                        <div className="cart-item-actions">
                                            <button 
                                                onClick={() => updateQuantity(item.cart_id, item.quantity - 1)}
                                                className="qty-btn"
                                            >-</button>
                                            <span className="qty-number">{item.quantity}</span>
                                            <button 
                                                onClick={() => updateQuantity(item.cart_id, item.quantity + 1)}
                                                className="qty-btn"
                                            >+</button>
                                            <button 
                                                onClick={() => removeItem(item.cart_id)}
                                                className="remove-btn"
                                                title="XГіa"
                                            >рџ—‘пёЏ</button>
                                        </div>
                                        <div className="cart-item-total">
                                            {formatPrice(item.price * item.quantity)}
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>

                        {cart.items?.length > 0 && (
                            <div className="cart-summary">
                                <div className="cart-total">
